  res.on('data', c => d += c);
  res.on('end', async () => {
    const targets = JSON.parse(d);
    const ot = targets.find(t => t.url.includes('onetalk') && t.type === 'iframe');
    if (!ot) { console.log('Not found'); process.exit(1); }

    // Parse ws URL
    const wsUrl = new URL(ot.webSocketDebuggerUrl);

    // Connect via raw TCP and do WebSocket handshake + send CDP command
    const socket = net.connect(wsUrl.port, wsUrl.hostname);

    let buf = '';
    socket.on('data', (data) => {
      buf += data.toString();
      // Parse WebSocket frames
      while (buf.length > 0) {
        // Find start of frame
        const idx = buf.indexOf('\\x81');
        if (idx === -1) break;
        buf = buf.substring(idx);
        if (buf.length < 2) break;
        const len = buf.charCodeAt(1) & 0x7f;
        let offset = 2;
        let payloadLen = len;
        if (len === 126) { if (buf.length < 4) break; payloadLen = buf.charCodeAt(2) << 8 | buf.charCodeAt(3); offset = 4; }
        else if (len === 127) { /* skip */ break; }
        if (buf.length < offset + payloadLen) break;

        const payload = buf.substring(offset, offset + payloadLen);
        try {
          const msg = JSON.parse(payload);
          if (msg.id === 1 && msg.result) {
            console.log(JSON.parse(msg.result.result.value));
            socket.end();
            process.exit(0);
          } else if (msg.error) {
            console.log('CDP error: ' + JSON.stringify(msg.error));
          }
        } catch(e) {}
        buf = buf.substring(offset + payloadLen);
      }
    });

    socket.on('connect', () => {
      // WebSocket handshake
      const key = Buffer.from('testkey12345678901234').toString('base64');
      socket.write([
        'GET ' + wsUrl.pathname + ' HTTP/1.1',
        'Host: ' + wsUrl.hostname + ':' + wsUrl.port,
        'Upgrade: websocket',
        'Connection: Upgrade',
        'Sec-WebSocket-Key: ' + key,
        'Sec-WebSocket-Version: 13',
        '', ''
      ].join('\\r\\n'));

      // Send Runtime.evaluate
      const expr = 'JSON.stringify({readyState:document.readyState,hidden:document.hidden,imSdk:!!window._imsdk,imBaaS:!!window._imBaaSSDK,isLogin:window._imsdk?window._imsdk._isLogin:null,convs:!!window.__conversationListFullData__})';
      const cmd = JSON.stringify({id:1,method:'Runtime.evaluate',params:{expression:expr}});
      const len = cmd.length;
      let frame;
      if (len < 126) {
        frame = Buffer.alloc(2 + len);
        frame[0] = 0x81; frame[1] = len;
        frame.write(cmd, 2);
      }
      socket.write(frame);
    });

    setTimeout(() => { console.log('timeout'); process.exit(1); }, 10000);
  });
});
