const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.connectOverCDP('http://localhost:9222');
  const client = await browser.contexts()[0].pages()[0].context().newCDPSession(browser.contexts()[0].pages()[0]);

  // Enable Runtime domain first
  await client.send('Runtime.enable');

  // Get targets
  const targets = await client.send('Target.getTargets');
  const ot = targets.targetInfos.find(t => t.url.includes('onetalk') && t.type === 'iframe');

  // Attach to iframe
  const { sessionId } = await client.send('Target.attachToTarget', { targetId: ot.targetId, flatten: false });

  // Set up listener for messages from the iframe session
  let result = null;
  client.on('Target.receivedMessageFromTarget', (msg) => {
    if (msg.sessionId === sessionId) {
      try {
        const response = JSON.parse(msg.message);
        if (response.id === 1 && response.result) {
          result = JSON.parse(response.result.result.value);
        }
      } catch(e) {}
    }
  });

  // Send evaluate command to iframe
  await client.send('Target.sendMessageToTarget', {
    sessionId: sessionId,
    message: JSON.stringify({
      id: 1,
      method: 'Runtime.evaluate',
      params: {
        expression: 'JSON.stringify({imSdk:!!window._imsdk,imBaaS:!!window._imBaaSSDK,isLogin:window._imsdk?window._imsdk._isLogin:null,convs:window.__conversationListFullData__?window.__conversationListFullData__.length:0})'
      }
    })
  });

  // Wait a bit for response
  await new Promise(r => setTimeout(r, 2000));

  if (result) {
    console.log(JSON.stringify(result));
  } else {
    console.log('No result received');
  }
  process.exit(0);
})().catch(e => { console.error(e.message); process.exit(1); });
