const { chromium } = require('playwright');

(async () => {
  const browser = await chromium.connectOverCDP('http://localhost:9222');
  const client = await browser.contexts()[0].pages()[0].context().newCDPSession(browser.contexts()[0].pages()[0]);

  const targets = await client.send('Target.getTargets');
  const ot = targets.targetInfos.find(t => t.url.includes('onetalk') && t.type === 'iframe');
  if (!ot) { console.log('onetalk iframe not found'); process.exit(1); }
  const { sessionId } = await client.send('Target.attachToTarget', { targetId: ot.targetId, flatten: false });

  let results = [];
  client.on('Target.receivedMessageFromTarget', (msg) => {
    if (msg.sessionId !== sessionId) return;
    try {
      const response = JSON.parse(msg.message);
      if (response.id && response.result) {
        const val = response.result.result ? response.result.result.value : null;
        if (val) results.push({ id: response.id, val: JSON.parse(val) });
      }
    } catch (e) { /* ignore */ }
  });

  // Try raw fetch() to known API endpoints
  const expr = `
    new Promise(async function(resolve) {
      var convs = window.__conversationListFullData__;
      var c = convs.find(function(x) { return x.latestMessage && x.latestMessage.content; });

      var results = {};

      // Try 1: listRecentConversation
      try {
        var fd1 = new URLSearchParams();
        fd1.append('conversationCode', c.cid);
        fd1.append('count', '5');
        var r1 = await fetch('https://onetalk.alibaba.com/message/listRecentConversation.htm', {
          method: 'POST',
          credentials: 'include',
          headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
          body: fd1.toString()
        });
        var t1 = await r1.text();
        results.listRecentConversation = { status: r1.status, preview: t1.substring(0, 300) };
      } catch(e) {
        results.listRecentConversation = { err: e.message };
      }

      // Try 2: listMessage with different paths
      var paths = [
        '/message/listMessage.htm',
        '/message/listPrevMessage.htm',
        '/message/imhistory.htm',
        '/message/queryMessage.htm',
        '/message/getMessageHistory.htm',
        '/message/listMessageByConversation.htm'
      ];

      for (var i = 0; i < paths.length; i++) {
        try {
          var fd = new URLSearchParams();
          fd.append('conversationCode', c.cid);
          fd.append('count', '5');
          var r = await fetch('https://onetalk.alibaba.com' + paths[i], {
            method: 'POST',
            credentials: 'include',
            headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
            body: fd.toString()
          });
          var t = await r.text();
          results[paths[i]] = { status: r.status, preview: t.substring(0, 200) };
        } catch(e) {
          results[paths[i]] = { err: e.message };
        }
      }

      resolve(JSON.stringify(results));
    })
  `;

  await client.send('Target.sendMessageToTarget', {
    sessionId: sessionId,
    message: JSON.stringify({
      id: 1,
      method: 'Runtime.evaluate',
      params: { expression: expr, awaitPromise: true }
    })
  });

  await new Promise(r => setTimeout(r, 30000));
  console.log(JSON.stringify(results, null, 2));
  process.exit(0);
})().catch(e => { console.error(e.message); process.exit(1); });

