const { chromium } = require('playwright');

(async () => {
  const browser = await chromium.connectOverCDP('http://localhost:9222');
  const client = await browser.contexts()[0].pages()[0].context().newCDPSession(browser.contexts()[0].pages()[0]);

  const targets = await client.send('Target.getTargets');
  const ot = targets.targetInfos.find(t => t.url.includes('onetalk') && t.type === 'iframe');
  if (!ot) { console.log('onetalk iframe not found'); process.exit(1); }
  const { sessionId } = await client.send('Target.attachToTarget', { targetId: ot.targetId, flatten: false });

  let results = [];
  client.on('Target.receivedMessageFromTarget', (msg) => {
    if (msg.sessionId !== sessionId) return;
    try {
      const response = JSON.parse(msg.message);
      if (response.id && response.result) {
        const val = response.result.result ? response.result.result.value : null;
        if (val) results.push({ id: response.id, val: JSON.parse(val) });
      } else if (response.id && response.error) {
        results.push({ id: response.id, err: response.error.message });
      }
    } catch (e) {}
  });

  // Test: sequential approach - reconnect, wait, check, fetch
  const expr = `
    (async function() {
      var results = {};
      var a = window._imsdk.getAuthService();
      var httpSvc = window._imBaaSSDK.getMessageServiceHttp();
      var convs = window.__conversationListFullData__;
      var c = convs.find(function(x) { return x.latestMessage && x.latestMessage.content; });

      // Step 1: Reconnect
      try {
        await a.reConnect();
        results.reconnect = 'ok';
      } catch(e) {
        results.reconnect = 'err: ' + (e && e.message || String(e));
      }

      // Step 2: Wait a bit for async connection
      await new Promise(function(r) { setTimeout(r, 3000); });

      // Step 3: Check status
      results.afterReconnect = {
        isLogin: a.isLogin(),
        connectionStatus: a.connectionStatus
      };

      // Step 4: Try HTTP service directly
      try {
        var r1 = await new Promise(function(resolve) {
          httpSvc.listMessageWithConversationCodeForHistory({
            conversationCode: c.cid,
            count: 5,
            dataCallback: function(r) { resolve({ source: 'http_listHistory', ok: true, n: r.data ? r.data.length : 0 }); },
            errorCallBack: function(e) { resolve({ source: 'http_listHistory', ok: false, err: e && e.message || String(e) }); }
          });
        });
        results.httpListHistory = r1;
      } catch(e) {
        results.httpListHistory = { err: e.message };
      }

      // Step 5: Try WS service (might work now after reconnect)
      try {
        var wsSvc = window._imsdk.getMessageService();
        var r2 = await new Promise(function(resolve) {
          wsSvc.listMessageWithConversationCodeForHistory({
            conversationCode: c.cid,
            count: 5,
            dataCallback: function(r) { resolve({ source: 'ws_listHistory', ok: true, n: r.data ? r.data.length : 0 }); },
            errorCallBack: function(e) { resolve({ source: 'ws_listHistory', ok: false, err: e && e.message || String(e) }); }
          });
        });
        results.wsListHistory = r2;
      } catch(e) {
        results.wsListHistory = { err: e.message };
      }

      return JSON.stringify(results);
    })()
  `;

  console.log('Sending evaluate (will wait up to 30s)...');
  await client.send('Target.sendMessageToTarget', {
    sessionId: sessionId,
    message: JSON.stringify({
      id: 1,
      method: 'Runtime.evaluate',
      params: { expression: expr, awaitPromise: true }
    })
  });

  // Wait longer
  await new Promise(r => setTimeout(r, 35000));
  console.log(JSON.stringify(results, null, 2));
  process.exit(0);
})().catch(e => { console.error(e.message); process.exit(1); });

