const { chromium } = require('playwright');

(async () => {
  const browser = await chromium.connectOverCDP('http://localhost:9222');
  const client = await browser.contexts()[0].pages()[0].context().newCDPSession(browser.contexts()[0].pages()[0]);

  const targets = await client.send('Target.getTargets');
  const ot = targets.targetInfos.find(t => t.url.includes('onetalk') && t.type === 'iframe');
  if (!ot) { console.log('onetalk iframe not found'); process.exit(1); }
  const { sessionId } = await client.send('Target.attachToTarget', { targetId: ot.targetId, flatten: false });

  let results = [];
  client.on('Target.receivedMessageFromTarget', (msg) => {
    if (msg.sessionId !== sessionId) return;
    try {
      const response = JSON.parse(msg.message);
      if (response.id && response.result) {
        const val = response.result.result ? response.result.result.value : null;
        if (val) results.push({ id: response.id, val: JSON.parse(val) });
      }
    } catch (e) {}
  });

  const expr = `
    (function() {
      var convs = window.__conversationListFullData__;

      // Show first 3 conversations' key data
      var samples = convs.slice(0, 3).map(function(c) {
        var lm = c.latestMessage;
        return {
          cid: c.cid ? c.cid.substring(0, 50) : 'none',
          name: c.name,
          loginId: c.loginId,
          aliId: c.aliId,
          conversationType: c.conversationType,
          unreadCount: c.unreadCount,
          lastContactTime: c.lastContactTime,
          hasLatestMsg: !!lm,
          latestMsgContent: lm ? (lm.content ? lm.content.substring(0, 80) : 'no content field') : 'no lm',
          latestMsgType: lm ? lm.messageType : 'N/A',
          latestMsgId: lm ? lm.messageId : 'N/A',
          latestMsgKeys: lm ? Object.keys(lm).join(',') : 'N/A'
        };
      });

      // Count conversations with latestMessage content
      var withContent = convs.filter(function(c) {
        return c.latestMessage && c.latestMessage.content && c.latestMessage.content.length > 0;
      }).length;

      // Get auth service info
      var a = window._imsdk.getAuthService();
      var authInfo = {
        isLogin: a.isLogin(),
        connectionStatus: a.connectionStatus,
        loginUid: a.getLoginUid()
      };

      return JSON.stringify({
        totalConvs: convs.length,
        convsWithContent: withContent,
        auth: authInfo,
        samples: samples
      }, null, 2);
    })()
  `;

  await client.send('Target.sendMessageToTarget', {
    sessionId: sessionId,
    message: JSON.stringify({ id: 1, method: 'Runtime.evaluate', params: { expression: expr } })
  });

  await new Promise(r => setTimeout(r, 3000));
  console.log(results[0] ? results[0].val : 'no result');
  process.exit(0);
})().catch(e => { console.error(e.message); process.exit(1); });

