  const ot = targets.targetInfos.find(t => t.url.includes('onetalk') && t.type === 'iframe');
  if (!ot) { console.log('onetalk iframe not found'); process.exit(1); }
  const { sessionId } = await client.send('Target.attachToTarget', { targetId: ot.targetId, flatten: false });

  let results = [];
  client.on('Target.receivedMessageFromTarget', (msg) => {
    if (msg.sessionId !== sessionId) return;
    try {
      const response = JSON.parse(msg.message);
      if (response.id && response.result) {
        const val = response.result.result ? response.result.result.value : null;
        if (val) results.push({ id: response.id, val: JSON.parse(val) });
      }
    } catch (e) {}
  });

  const expr = `
    (async function() {
      var results = {};
      var convs = window.__conversationListFullData__;
      var c = convs[0]; // Use first conversation
      var httpSvc = window._imBaaSSDK.getMessageServiceHttp();
      var wsSvc = window._imsdk.getMessageService();
      var now = Date.now();

      // Try various parameter combinations
      var attempts = [];

      // 1. HTTP service with cursor
      try {
        var r = await new Promise(function(resolve) {
          httpSvc.listMessageWithConversationCodeForHistory({
            conversationCode: c.cid,
            count: 5,
            cursor: { sendTime: now },
            dataCallback: function(r) { resolve({ ok: true, n: r.data ? r.data.length : 0, hasMore: r.hasMore }); },
            errorCallBack: function(e) { resolve({ ok: false, err: e && e.message || String(e) }); }
          });
        });
        attempts.push({ method: 'http+cursor', result: r });
      } catch(e) {
        attempts.push({ method: 'http+cursor', result: { err: e.message } });
      }

      // 2. HTTP service WITHOUT cursor
      try {
        var r = await new Promise(function(resolve) {
          httpSvc.listMessageWithConversationCodeForHistory({
            conversationCode: c.cid,
            count: 5,
            dataCallback: function(r) { resolve({ ok: true, n: r.data ? r.data.length : 0, hasMore: r.hasMore }); },
            errorCallBack: function(e) { resolve({ ok: false, err: e && e.message || String(e) }); }
          });
        });
        attempts.push({ method: 'http+noCursor', result: r });
      } catch(e) {
        attempts.push({ method: 'http+noCursor', result: { err: e.message } });
      }

      // 3. WS service with cursor
      try {
        var r = await new Promise(function(resolve) {
          wsSvc.listMessageWithConversationCodeForHistory({
            conversationCode: c.cid,
            count: 5,
            cursor: { sendTime: now },
            dataCallback: function(r) { resolve({ ok: true, n: r.data ? r.data.length : 0, hasMore: r.hasMore }); },
            errorCallBack: function(e) { resolve({ ok: false, err: e && e.message || String(e) }); }
          });
        });
        attempts.push({ method: 'ws+cursor', result: r });
      } catch(e) {
        attempts.push({ method: 'ws+cursor', result: { err: e.message } });
      }

      // 4. Try listMessageWithConversationCode (not history)
      try {
        var r = await new Promise(function(resolve) {
          httpSvc.listMessageWithConversationCode({
            conversationCode: c.cid,
            count: 5,
            dataCallback: function(r) { resolve({ ok: true, n: r.data ? r.data.length : 0, hasMore: r.hasMore }); },
            errorCallBack: function(e) { resolve({ ok: false, err: e && e.message || String(e) }); }
          });
        });
        attempts.push({ method: 'http+listConv', result: r });
      } catch(e) {
        attempts.push({ method: 'http+listConv', result: { err: e.message } });
      }

      // 5. Try fetchMessages with timeStamp
      try {
        var r = await httpSvc.fetchMessages({
          conversationCode: c.cid,
          count: 5,
          timeStamp: now
        });
        attempts.push({ method: 'fetchMsgs+tsRaw', result: { raw: JSON.stringify(r).substring(0, 200) } });
      } catch(e) {
        attempts.push({ method: 'fetchMsgs+tsRaw', result: { err: e.message } });
      }

      results.cid = c.cid;
      results.name = c.name;
      results.latestMsgContent = c.latestMessage ? c.latestMessage.content : 'none';
      results.latestMsgTime = c.latestMessage ? c.latestMessage.gmtChat : 'none';
      results.attempts = attempts;

      return JSON.stringify(results);
    })()
  `;

  console.log('Testing multiple fetch methods...');
  await client.send('Target.sendMessageToTarget', {
    sessionId: sessionId,
    message: JSON.stringify({
      id: 1,
      method: 'Runtime.evaluate',
      params: { expression: expr, awaitPromise: true }
    })
  });

  await new Promise(r => setTimeout(r, 25000));
  console.log(JSON.stringify(results, null, 2));
  process.exit(0);
})().catch(e => { console.error(e.message); process.exit(1); });

