const { chromium } = require('playwright');

(async () => {
  const browser = await chromium.connectOverCDP('http://localhost:9222');
  const client = await browser.contexts()[0].pages()[0].context().newCDPSession(browser.contexts()[0].pages()[0]);

  const targets = await client.send('Target.getTargets');
  const ot = targets.targetInfos.find(t => t.url.includes('onetalk') && t.type === 'iframe');
  if (!ot) { console.log('onetalk iframe not found'); process.exit(1); }
  const { sessionId } = await client.send('Target.attachToTarget', { targetId: ot.targetId, flatten: false });

  let results = [];
  client.on('Target.receivedMessageFromTarget', (msg) => {
    if (msg.sessionId !== sessionId) return;
    try {
      const response = JSON.parse(msg.message);
      if (response.id && response.result) {
        const val = response.result.result ? response.result.result.value : null;
        if (val) results.push({ id: response.id, val: JSON.parse(val) });
      }
    } catch (e) {}
  });

  const expr = `
    (function() {
      // Search ALL scripts for API URLs
      var scripts = document.querySelectorAll('script[src]');
      var results = {};

      // Also check for /message/ endpoints in all script text
      var allText = '';
      try {
        var inlineScripts = document.querySelectorAll('script:not([src])');
        inlineScripts.forEach(function(s) { allText += s.textContent.substring(0, 2000); });
      } catch(e) {}

      // Look for message-related API URLs in inline scripts
      var messageApis = allText.match(/\\/message\\/[a-zA-Z]+/g) || [];
      var apiUrls = allText.match(/https?:\\/\\/[a-z.-]+\\/[a-zA-Z0-9_\\/.-]*message[a-zA-Z0-9_\\/.-]*/gi) || [];
      var mtopApis = allText.match(/mtop\\.[a-zA-Z0-9_.]+/g) || [];

      // Unique them
      results.messagePaths = [...new Set(messageApis)];
      results.apiUrls = [...new Set(apiUrls)].slice(0, 20);
      results.mtopApis = [...new Set(mtopApis)].slice(0, 20);
      results.inlineScriptCount = document.querySelectorAll('script:not([src])').length;
      results.scriptUrls = Array.from(scripts).map(function(s) { return s.src.substring(s.src.lastIndexOf('/')+1); });

      return JSON.stringify(results);
    })()
  `;

  await client.send('Target.sendMessageToTarget', {
    sessionId: sessionId,
    message: JSON.stringify({
      id: 1,
      method: 'Runtime.evaluate',
      params: { expression: expr }
    })
  });

  await new Promise(r => setTimeout(r, 3000));
  console.log(JSON.stringify(results, null, 2));
  process.exit(0);
})().catch(e => { console.error(e.message); process.exit(1); });

