    (async function() {
      var results = {};
      var convs = window.__conversationListFullData__;

      // Try the first 5 conversations that have latestMessage content
      var targets = convs.filter(function(c) {
        return c.latestMessage && c.latestMessage.content && c.latestMessage.content.length > 0;
      }).slice(0, 5);

      // Use WS service this time
      var wsSvc = window._imsdk.getMessageService();

      for (var i = 0; i < targets.length; i++) {
        var c = targets[i];
        try {
          var r = await new Promise(function(resolve) {
            wsSvc.listMessageWithConversationCodeForHistory({
              conversationCode: c.cid,
              count: 20,
