const { chromium } = require('playwright');

(async () => {
  const browser = await chromium.connectOverCDP('http://localhost:9222');
  const client = await browser.contexts()[0].pages()[0].context().newCDPSession(browser.contexts()[0].pages()[0]);

  const targets = await client.send('Target.getTargets');
  const ot = targets.targetInfos.find(t => t.url.includes('onetalk') && t.type === 'iframe');
  if (!ot) { console.log('onettalk iframe not found'); process.exit(1); }
  const { sessionId } = await client.send('Target.attachToTarget', { targetId: ot.targetId, flatten: false });

  let results = [];
  client.on('Target.receivedMessageFromTarget', (msg) => {
    if (msg.sessionId !== sessionId) return;
    try {
      const response = JSON.parse(msg.message);
      if (response.id && response.result) {
        const val = response.result.result ? response.result.result.value : null;
        if (val) results.push({ id: response.id, val: JSON.parse(val) });
      }
    } catch (e) {}
  });

  const expr = `
    (async function() {
      var results = {};
      var httpSvc = window._imBaaSSDK.getMessageServiceHttp();
      var convs = window.__conversationListFullData__;

      // Try conversation with most recent contact time
      var sorted = convs.slice().sort(function(a, b) {
        return (b.lastContactTime || 0) - (a.lastContactTime || 0);
      });
      var recent = sorted[0];

      // Try searchRemoteMessage
      try {
        var r = await new Promise(function(resolve) {
          httpSvc.searchRemoteMessage({
            conversationCode: recent.cid,
            keyWord: '',
            count: 20,
            dataCallback: function(r) { resolve({ ok: true, n: r.data ? r.data.length : 0 }); },
            errorCallBack: function(e) { resolve({ ok: false, err: e && e.message || String(e) }); }
          });
        });
        results.searchRemote = r;
      } catch(e) {
        results.searchRemote = { err: e.message };
      }

      // Also try: get the conversation object's full inner structure
      // The 'contact' field might have more data
      results.contactSample = {
        keys: recent.contact ? Object.keys(recent.contact) : [],
        hasFullPortrait: recent.contact && !!recent.contact.fullPortrait
      };

      // Check if there are any other global stores
      var storeKeys = Object.keys(window).filter(function(k) {
        return k.includes('Store') || k.includes('store') || k.includes('cache') || k.includes('Cache') || k.includes('data');
      });
      results.storeKeys = storeKeys;

      // Check React fiber for message data - look at root element
      var root = document.getElementById('__next') || document.getElementById('root') || document.body.firstElementChild;
      var fiberKey = Object.keys(root).find(function(k) { return k.startsWith('__react') || k.startsWith('__reactFiber'); });
      results.hasFiber = !!fiberKey;

      return JSON.stringify(results);
    })()
  `;

  console.log('Trying searchRemoteMessage and checking data stores...');
  await client.send('Target.sendMessageToTarget', {
    sessionId: sessionId,
    message: JSON.stringify({
      id: 1,
      method: 'Runtime.evaluate',
      params: { expression: expr, awaitPromise: true }
    })
  });

  await new Promise(r => setTimeout(r, 15000));
  console.log(JSON.stringify(results, null, 2));
  process.exit(0);
})().catch(e => { console.error(e.message); process.exit(1); });

